Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest cancels via TestContext.CancellationToken after 3s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken so the test cooperatively
        // aborts if the timeout fires — no hanging test.
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — token that's already cancelled
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var handler = new FakeHandler("data", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_CancelledDuringRequest_ThrowsTaskCanceledException()
    {
        // Arrange — handler that simulates a slow response
        using var cts = new CancellationTokenSource();
        var handler = new SlowHandler(cts); // cancels mid-flight
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test doubles ---

    private sealed class FakeHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            });
        }
    }

    private sealed class SlowHandler(CancellationTokenSource cts)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cts.Cancel();                              // simulate cancel mid-request
            await Task.Delay(500, cancellationToken);  // throws TaskCanceledException
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — test aborts cleanly instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Exact exception type match, replaces `[ExpectedException]` |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over `HttpClient` |
| `sealed` test class | MSTest best practice for performance |

The critical insight: **always flow `TestContext.CancellationToken`** into any async call inside a `[Timeout]` test. Without it, the timeout fires but the test hangs because nothing signals the `await` to stop.
